import{_ as h,o as i,c as a,ag as t}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Đánh giá & Phản hồi","description":"","frontmatter":{},"headers":[],"relativePath":"evaluation.md","filePath":"evaluation.md"}'),o={name:"evaluation.md"};function c(g,n,r,u,l,e){return i(),a("div",null,[...n[0]||(n[0]=[t('<h1 id="đanh-gia-phan-hoi" tabindex="-1">Đánh giá &amp; Phản hồi <a class="header-anchor" href="#đanh-gia-phan-hoi" aria-label="Permalink to &quot;Đánh giá &amp; Phản hồi&quot;">​</a></h1><blockquote><p>Nhận phản hồi chuyên môn, chi tiết từng câu nói đến toàn bộ cuộc trò chuyện.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Sau mỗi bài thực hành, AI Coach tự động tạo một báo cáo đánh giá chi tiết với 3 cấp độ phân tích:</p><ol><li><strong>Đánh giá Giai đoạn</strong> — Việc hoàn thành các giai đoạn bán hàng và gợi ý cải thiện.</li><li><strong>Đánh giá Toàn diện</strong> — Tóm tắt hiệu suất tổng thể và định hướng học tập.</li><li><strong>Đánh giá Từng câu</strong> — Phân tích chi tiết từng tin nhắn.</li></ol><hr><h2 id="giao-dien-bao-cao-đanh-gia" tabindex="-1">Giao diện Báo cáo Đánh giá <a class="header-anchor" href="#giao-dien-bao-cao-đanh-gia" aria-label="Permalink to &quot;Giao diện Báo cáo Đánh giá&quot;">​</a></h2><p>Khi mở báo cáo (từ nút &quot;Xem Đánh giá&quot; trong Lịch sử), giao diện được chia làm các phần chính:</p><h3 id="thanh-cong-cu-tuy-chon-che-đo-xem" tabindex="-1">Thanh Công cụ &amp; Tùy chọn Chế độ Xem <a class="header-anchor" href="#thanh-cong-cu-tuy-chon-che-đo-xem" aria-label="Permalink to &quot;Thanh Công cụ &amp; Tùy chọn Chế độ Xem&quot;">​</a></h3><ul><li><strong>Nút Trở về:</strong> Quay lại danh sách Lịch sử hoặc Bảng điều khiển.</li><li><strong>Trình chuyển đổi Ngôn ngữ:</strong> Đổi ngôn ngữ báo cáo.</li><li><strong>Nút Chuyển đổi Chế độ Xem:</strong> Một nút nổi bật để chuyển đổi giữa hai chế độ: <ul><li><strong>Đánh giá Toàn diện (Mặc định)</strong>: Xem Đánh giá Giai đoạn và Đánh giá Toàn diện.</li><li><strong>Đánh giá Từng câu (檢視逐句評價)</strong>: Đi sâu vào phân tích từng tin nhắn.</li></ul></li></ul><h3 id="bang-thong-tin-chan-dung-bang-phia-phai" tabindex="-1">Bảng Thông tin Chân dung (Bảng Phía Phải) <a class="header-anchor" href="#bang-thong-tin-chan-dung-bang-phia-phai" aria-label="Permalink to &quot;Bảng Thông tin Chân dung (Bảng Phía Phải)&quot;">​</a></h3><p>Luôn hiển thị trên màn hình để bạn đối chiếu nhận xét của AI với ngữ cảnh khách hàng:</p><ul><li><strong>Kiểu tính cách (MBTI):</strong> Ví dụ INTJ (Kiến trúc sư). Rất quan trọng để hiểu phong cách ra quyết định của khách hàng.</li><li><strong>Chi tiết Khách hàng:</strong> Học vấn, Tình trạng hôn nhân, Cấp độ thu nhập.</li><li><strong>Mối quan hệ:</strong> Quan hệ hiện tại giữa khách và Tư vấn viên.</li></ul><hr><h2 id="qua-trinh-tao-bao-cao" tabindex="-1">Quá trình Tạo Báo cáo <a class="header-anchor" href="#qua-trinh-tao-bao-cao" aria-label="Permalink to &quot;Quá trình Tạo Báo cáo&quot;">​</a></h2><h3 id="thoi-điem-kich-hoat" tabindex="-1">Thời điểm Kích hoạt <a class="header-anchor" href="#thoi-điem-kich-hoat" aria-label="Permalink to &quot;Thời điểm Kích hoạt&quot;">​</a></h3><p>Khi bạn nhấp &quot;Kết thúc trò chuyện&quot;, hệ thống: Đóng trò chuyện → Kích hoạt 3 tác vụ nền:</p><ul><li>Tạo Đánh giá Giai đoạn</li><li>Tạo Đánh giá Toàn diện</li><li>Tạo Tóm tắt Cuộc gọi</li></ul><blockquote><p>Lưu ý: Đánh giá Từng câu được tạo ở chế độ nền trong suốt quá trình trò chuyện, ngay sau mỗi tin nhắn.</p></blockquote><h3 id="trang-thai-giao-dien" tabindex="-1">Trạng thái Giao diện <a class="header-anchor" href="#trang-thai-giao-dien" aria-label="Permalink to &quot;Trạng thái Giao diện&quot;">​</a></h3><p>Quá trình tạo thường mất từ 30 giây đến 2 phút.</p><hr><h2 id="_1-đanh-gia-giai-đoan" tabindex="-1">1. Đánh giá Giai đoạn <a class="header-anchor" href="#_1-đanh-gia-giai-đoan" aria-label="Permalink to &quot;1. Đánh giá Giai đoạn&quot;">​</a></h2><p>AI đánh giá toàn bộ cuộc trò chuyện một lần dựa trên các tiêu chuẩn do quản trị viên thiết lập để xác định bạn đã đạt đến giai đoạn bán hàng nào.</p><h3 id="đau-ra" tabindex="-1">Đầu ra <a class="header-anchor" href="#đau-ra" aria-label="Permalink to &quot;Đầu ra&quot;">​</a></h3><p>Đối với mỗi giai đoạn đạt được, thẻ đánh giá sẽ cung cấp phân tích. Nếu bạn không thể thăng cấp lên giai đoạn tiếp theo, một phần &quot;Lý do Không Thăng cấp&quot; sẽ giải thích những gì bạn cần cải thiện.</p><hr><h2 id="_2-đanh-gia-toan-dien" tabindex="-1">2. Đánh giá Toàn diện <a class="header-anchor" href="#_2-đanh-gia-toan-dien" aria-label="Permalink to &quot;2. Đánh giá Toàn diện&quot;">​</a></h2><p>Không giống Đánh giá Giai đoạn, Đánh giá Toàn diện xem xét màn thể hiện của bạn từ góc độ kỹ năng mềm: chất lượng hội thoại, kỹ năng bán hàng, tạo dựng mối quan hệ, và thể hiện sự chuyên nghiệp.</p><h3 id="đau-ra-1" tabindex="-1">Đầu ra <a class="header-anchor" href="#đau-ra-1" aria-label="Permalink to &quot;Đầu ra&quot;">​</a></h3><p>Báo cáo bằng Markdown bao gồm:</p><ul><li>Tổng quan hiệu suất</li><li>Đánh giá Điểm mạnh</li><li>Lĩnh vực Cần Cải thiện</li><li>Đề xuất Bước đi Tiếp theo</li></ul><hr><h2 id="_3-đanh-gia-tung-cau" tabindex="-1">3. Đánh giá Từng câu <a class="header-anchor" href="#_3-đanh-gia-tung-cau" aria-label="Permalink to &quot;3. Đánh giá Từng câu&quot;">​</a></h2><p>Cấp độ phản hồi chi tiết nhất, phân tích từng tin nhắn của bạn đang diễn ra. Chuyển sang chế độ này bằng nút &quot;Đánh giá Từng câu&quot; trên thanh công cụ.</p><h3 id="cach-thuc-hoat-đong" tabindex="-1">Cách thức Hoạt động <a class="header-anchor" href="#cach-thuc-hoat-đong" aria-label="Permalink to &quot;Cách thức Hoạt động&quot;">​</a></h3><p>Tính năng này chạy ngầm trong suốt buổi thực hành. Khi bạn chuyển sang tab Đánh giá Từng câu, bạn có thể xem lại:</p><ul><li><strong>Suy nghĩ nội tâm của AI:</strong> Điều khách hàng đang thực sự nghĩ nhưng không nói ra.</li><li>Phản hồi chi tiết cho từng tin nhắn: Cách diễn đạt, hiệu quả sử dụng kỹ năng.</li></ul><hr><h2 id="cung-cap-phan-hoi-cho-phan-tich-cua-ai" tabindex="-1">Cung cấp Phản hồi cho Phân tích của AI <a class="header-anchor" href="#cung-cap-phan-hoi-cho-phan-tich-cua-ai" aria-label="Permalink to &quot;Cung cấp Phản hồi cho Phân tích của AI&quot;">​</a></h2><p>Bên dưới Đánh giá Toàn diện và mỗi mục Từng câu, bạn có thể nhấn Thích/Không Thích để cung cấp phản hồi về chất lượng phân tích của hệ thống AI, qua đó giúp cải thiện hệ thống trong tương lai.</p><h2 id="loi-khuyen" tabindex="-1">Lời khuyên <a class="header-anchor" href="#loi-khuyen" aria-label="Permalink to &quot;Lời khuyên&quot;">​</a></h2><ol><li>Đọc <strong>Đánh giá Giai đoạn</strong> để biết bạn đã làm tốt ở bước nào.</li><li>Kiểm tra phần <strong>Không thăng cấp</strong> để xem thiếu sót.</li><li>Đọc <strong>Đánh giá Toàn diện</strong> để biết định hướng.</li><li>Nhấc tab <strong>Đánh giá Từng câu</strong> và chú ý phần <strong>Suy nghĩ nội tâm của AI</strong> để thấu hiểu tâm lý khách hàng dựa trên MBTI của họ.</li></ol>',43)])])}const p=h(o,[["render",c]]);export{d as __pageData,p as default};
